// Normalize input – unterstützt 3 Trigger-Formate:
//
// Format A – Znuny Invoker (Ticket::Generic):
//   { Event: { Event: 'TicketCreate', TicketID: '42' }, Ticket: { TicketID: 42, Title: '...', DynamicField_Wer: '...', ... } }
//   → ticket_id extrahieren + volles Ticket-Objekt direkt weitergeben (kein separater API-Call nötig)
//
// Format B – GenericAgent / Simple Webhook:
//   { ticket_id: 42 }  oder  { TicketID: 42 }
//   → nur ticket_id, Ticket muss via SUB: Znuny Ticket Reader geholt werden
//
// Format C – Manual Trigger:
//   kein Payload → Test-Ticket-ID 1

const raw = $input.first().json;
// n8n Webhook-Node wraps payload in .body; manual trigger/other has it directly
const input = raw.body && (raw.body.Event || raw.body.Ticket || raw.body.ticket_id || raw.body.TicketID) ? raw.body : raw;

let ticket_id = null;
let ticket_data = null; // volles Ticket-Objekt falls vorhanden
let source = 'unknown';

// Format A: Znuny Invoker-Payload mit vollem Ticket-Objekt
if (input.Event && input.Ticket) {
  const t = Array.isArray(input.Ticket) ? input.Ticket[0] : input.Ticket;
  ticket_id = Number(t.TicketID || input.Event?.TicketID);
  source = 'znuny_invoker';
  // DynamicFields direkt aus Invoker-Payload extrahieren
  const getDynField = (name) => t[`DynamicField_${name}`] ?? null;
  ticket_data = {
    ticket_id,
    ticket_number: t.TicketNumber || `TN-${ticket_id}`,
    title: t.Title || `Ticket ${ticket_id}`,
    wer: getDynField('ZabbixWer') || getDynField('Wer') || getDynField('Device') || getDynField('Hostname') || 'unknown',
    was: getDynField('ZabbixWas') || getDynField('Was') || getDynField('ProbableCause') || t.Title || 'unknown',
    wan: getDynField('ZabbixWann') || getDynField('Wan') || getDynField('IncidentTime') || t.Created || new Date().toISOString(),
    priority: t.Priority || 'normal',
    status: t.State || 'new',
    queue: t.Queue || 'unknown',
    owner: t.Owner || 'unknown'
  };
}

// Format B: Einfache Webhook-Payload mit ticket_id
else if (input.ticket_id || input.TicketID || input.body?.ticket_id) {
  ticket_id = Number(input.ticket_id || input.TicketID || input.body?.ticket_id);
  source = 'webhook_simple';
}

// Format C: Manueller Trigger (Test)
else {
  ticket_id = 1;
  source = 'manual';
}

return [{
  json: {
    ticket_id,
    source,
    triggered_at: new Date().toISOString(),
    ticket_data_prefilled: ticket_data !== null, // Flag: kein Znuny-Reader-Call nötig
    ticket_data // null wenn nicht vorhanden
  }
}];

// Merge ticket data + NetBox system info into unified context
const trigger = $('🔧 Normalize Input').first().json;
// Bei Invoker-Payload: Ticket-Daten kommen direkt aus Normalize Input
// Bei Simple-Webhook: Ticket-Daten kommen aus SUB: Znuny Ticket Reader
const ticketData = trigger.ticket_data_prefilled
  ? trigger.ticket_data
  : $('🔗 SUB: Znuny Ticket Reader').first().json;
const netboxItems = $('🔗 SUB: NetBox Lookup').all();

// Get first system with IP from NetBox
const systemInfo = netboxItems.find(i => i.json && i.json.ip && i.json.name !== 'NO_SYSTEMS_FOUND')
  ? netboxItems.find(i => i.json && i.json.ip && i.json.name !== 'NO_SYSTEMS_FOUND').json
  : netboxItems[0]?.json || {};

const systemFound = systemInfo.ip && systemInfo.name !== 'NO_SYSTEMS_FOUND';

return [{
  json: {
    // Ticket info
    ticket_id: ticketData.ticket_id || trigger.ticket_id,
    title: ticketData.title || `Ticket ${trigger.ticket_id}`,
    wer: ticketData.wer || 'unknown',
    was: ticketData.was || 'unknown',
    wan: ticketData.wan || new Date().toISOString(),
    priority: ticketData.priority || 'normal',
    // System info from NetBox
    system_found: systemFound,
    system_id: systemInfo.id || null,
    system_name: systemInfo.name || ticketData.wer || 'unknown',
    system_ip: systemInfo.ip || null,
    system_type: systemInfo.type || 'unknown',
    ssh_user: systemInfo.ssh_user || 'root',
    ssh_password: systemInfo.ssh_password || '',
    topology: JSON.stringify({ type: systemInfo.type, cluster: systemInfo.cluster, id: systemInfo.id }),
    // Proxmox SSH access for LXC
    proxmox_host: '10.1.1.100',
    lxc_id: systemInfo.type === 'lxc' ? systemInfo.id : null,
    // Workflow tracking
    attempt: 1,
    retry_count: 0,
    incident_id: `INC-${trigger.ticket_id}-${Date.now()}`,
    started_at: new Date().toISOString()
  }
}];

// Build RCA prompt for Claude (Attempt 1)
const ctx = $('🔧 Initialize Context').first().json;

const sshInfo = ctx.lxc_id
  ? `Für LXC Container: ssh root@${ctx.proxmox_host} -t 'pct exec ${ctx.lxc_id} -- bash -c "<cmd>"'`
  : ctx.system_ip
    ? `Direktes SSH: ssh ${ctx.ssh_user}@${ctx.system_ip}`
    : `Proxmox SSH: root@${ctx.proxmox_host} (System-ID unbekannt)`;

const prompt = `Du bist ein autonomer DevOps/Network-Engineer. Analysiere den folgenden Incident via SSH und führe eine Root-Cause-Analysis (RCA) durch.

Incident-Details:
- Device/Host: ${ctx.wer}
- Probable Cause: ${ctx.was}
- Zeitpunkt: ${ctx.wan}
- System IP: ${ctx.system_ip || 'unbekannt'}
- System-Typ: ${ctx.system_type || 'unbekannt'}
- Topologie: ${ctx.topology}

SSH-Zugang:
${sshInfo}

Sammle Logs, Metriken und Systemstatus. Analysiere was wirklich passiert ist.

Antworte NUR als JSON (KEIN Markdown-Codeblock darum):
{
  "rca_text": "<detaillierte Root-Cause-Analyse>",
  "confidence_pct": <0-100>,
  "affected_component": "<betroffene Komponente>",
  "suggested_approach": "<empfohlener Lösungsansatz>"
}`;

return [{
  json: {
    ...ctx,
    prompt,
    system_prompt: 'You are an expert DevOps/Network incident response engineer. Perform SSH-based root cause analysis and respond ONLY with valid JSON, no markdown formatting.',
    context: `Device: ${ctx.wer}, Issue: ${ctx.was}, Time: ${ctx.wan}`
  }
}];

// Parse Claude RCA response
const claude_output = $input.first().json;
const ctx = $('🔧 Initialize Context').first().json;

let rca = {
  rca_text: 'Analyse fehlgeschlagen – keine verwertbare Antwort',
  confidence_pct: 0,
  affected_component: 'unbekannt',
  suggested_approach: 'Manuelle Überprüfung erforderlich'
};

try {
  const text = claude_output.response_text || '{}';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) rca = { ...rca, ...JSON.parse(match[0]) };
} catch(e) {
  rca.rca_text = `Parse-Fehler: ${e.message}. Raw: ${String(claude_output.response_text || '').slice(0, 300)}`;
}

const note_body = `## RCA Analyse (Versuch 1)\n\n**Root Cause:**\n${rca.rca_text}\n\n**Betroffene Komponente:** ${rca.affected_component}\n\n**Confidence:** ${rca.confidence_pct}%\n\n**Empfohlener Lösungsansatz:**\n${rca.suggested_approach}`;

return [{
  json: {
    ...ctx,
    rca,
    note_title: '🔍 RCA Analyse – Versuch 1',
    note_body
  }
}];

// Build Guide prompt using RCA results
const rca_data = $('🔧 Parse RCA Result').first().json;
const ctx = $('🔧 Initialize Context').first().json;

const prompt = `Basierend auf der RCA-Analyse soll ein konkreter Lösungs-Guide erstellt werden.

RCA Ergebnis:
- Root Cause: ${rca_data.rca?.rca_text}
- Betroffene Komponente: ${rca_data.rca?.affected_component}
- Empfohlener Ansatz: ${rca_data.rca?.suggested_approach}

System: ${ctx.wer} (IP: ${ctx.system_ip || 'unbekannt'}, Typ: ${ctx.system_type})

Erstelle einen Schritt-für-Schritt Lösungs-Guide mit konkreten Befehlen.

Antworte NUR als JSON:
{
  "guide_title": "<Titel>",
  "guide_steps": [
    {
      "step_nr": 1,
      "description": "<Beschreibung>",
      "commands": ["<befehl1>", "<befehl2>"],
      "expected_result": "<erwartetes Ergebnis>",
      "risk_level": "low|medium|high"
    }
  ]
}`;

return [{
  json: {
    ...ctx,
    rca: rca_data.rca,
    prompt,
    system_prompt: 'You are an expert DevOps engineer creating a step-by-step remediation guide. Respond ONLY with valid JSON.',
    context: `RCA: ${rca_data.rca?.rca_text?.slice(0, 200)}`
  }
}];

// Parse Claude Guide response
const claude_output = $input.first().json;
const ctx = $('🔧 Initialize Context').first().json;
const rca = $('🔧 Parse RCA Result').first().json.rca;

let guide = { guide_title: 'Lösungs-Guide', guide_steps: [] };

try {
  const text = claude_output.response_text || '{}';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) guide = { ...guide, ...JSON.parse(match[0]) };
} catch(e) {
  guide.guide_steps = [{ step_nr: 1, description: `Parse error: ${e.message}`, commands: [], expected_result: '', risk_level: 'unknown' }];
}

const stepsFormatted = guide.guide_steps.map(s =>
  `**Step ${s.step_nr}:** ${s.description}\n\`\`\`\n${(s.commands || []).join('\n')}\n\`\`\`\nErwartet: ${s.expected_result} | Risiko: ${s.risk_level}`
).join('\n\n');

const note_body = `## Lösungs-Guide (Versuch 1)\n\n**${guide.guide_title}**\n\n${stepsFormatted}`;

return [{
  json: {
    ...ctx,
    rca,
    guide,
    note_title: '📋 Lösungs-Guide – Versuch 1',
    note_body
  }
}];

// Build Execute prompt
const guide_data = $('🔧 Parse Guide Result').first().json;
const ctx = $('🔧 Initialize Context').first().json;

const stepsJson = JSON.stringify(guide_data.guide?.guide_steps || []);
const sshCmd = ctx.lxc_id
  ? `pct exec ${ctx.lxc_id} -- bash -c '<cmd>'  (auf Proxmox ${ctx.proxmox_host})`
  : `ssh ${ctx.ssh_user}@${ctx.system_ip}`;

const prompt = `Setze den folgenden Lösungs-Guide via SSH um.

Guide-Steps: ${stepsJson}

System: ${ctx.wer} (IP: ${ctx.system_ip || 'unbekannt'})
SSH-Zugang: ${sshCmd}

Führe jeden Schritt aus und dokumentiere das Ergebnis.

Antworte NUR als JSON:
{
  "steps_executed": [
    {
      "step_nr": 1,
      "command_run": "<ausgeführter Befehl>",
      "stdout": "<Ausgabe (max 500 Zeichen)>",
      "success": true
    }
  ],
  "all_success": true,
  "errors": []
}`;

return [{
  json: {
    ...ctx,
    rca: guide_data.rca,
    guide: guide_data.guide,
    prompt,
    system_prompt: 'You are an expert DevOps engineer executing remediation steps via SSH. Respond ONLY with valid JSON.',
    context: `System: ${ctx.wer}, Guide: ${guide_data.guide?.guide_title}`
  }
}];

// Parse Claude Execute response
const claude_output = $input.first().json;
const ctx = $('🔧 Initialize Context').first().json;
const rca = $('🔧 Parse RCA Result').first().json.rca;
const guide = $('🔧 Parse Guide Result').first().json.guide;

let execution = { steps_executed: [], all_success: false, errors: [] };

try {
  const text = claude_output.response_text || '{}';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) execution = { ...execution, ...JSON.parse(match[0]) };
} catch(e) {
  execution.errors = [`Parse error: ${e.message}`];
}

const stepsLog = (execution.steps_executed || []).map(s =>
  `**Step ${s.step_nr}:** \`${s.command_run}\`\n→ ${s.success ? '✅' : '❌'} ${String(s.stdout || '').slice(0, 300)}`
).join('\n\n');

const note_body = `## Ausführungs-Log (Versuch 1)\n\n**Alle Steps erfolgreich:** ${execution.all_success ? '✅ JA' : '❌ NEIN'}\n\n${stepsLog}${execution.errors?.length > 0 ? '\n\n**Fehler:**\n' + execution.errors.map(e => typeof e === 'object' ? JSON.stringify(e) : String(e)).join('\n') : ''}`;

return [{
  json: {
    ...ctx,
    rca,
    guide,
    execution,
    note_title: '💻 Ausführungs-Log – Versuch 1',
    note_body
  }
}];

// Build Verify prompt
const exec_data = $('🔧 Parse Execute Result').first().json;
const ctx = $('🔧 Initialize Context').first().json;

const prompt = `Verifiziere ob der Incident behoben wurde.

Original-Incident:
- Device: ${ctx.wer}
- Problem: ${ctx.was}
- Zeitpunkt: ${ctx.wan}
- Soll-Zustand: ${exec_data.rca?.suggested_approach || 'normaler Betrieb'}

Ausgeführte Maßnahmen: ${JSON.stringify(exec_data.execution?.steps_executed || [])}

SSH-Zugang: ${ctx.lxc_id ? `pct exec ${ctx.lxc_id} -- bash -c '<cmd>' auf ${ctx.proxmox_host}` : `ssh ${ctx.ssh_user}@${ctx.system_ip}`}

Prüfe via SSH ob das Problem behoben ist. Vergleiche Soll vs Ist.

Antworte NUR als JSON:
{
  "resolved": true,
  "soll_ist_comparison": "<Soll vs Ist Vergleich>",
  "remaining_issues": [],
  "verification_method": "<wie wurde geprüft>"
}`;

return [{
  json: {
    ...ctx,
    rca: exec_data.rca,
    guide: exec_data.guide,
    execution: exec_data.execution,
    prompt,
    system_prompt: 'You are an expert DevOps engineer verifying incident resolution via SSH. Respond ONLY with valid JSON.',
    context: `System: ${ctx.wer}, Original issue: ${ctx.was}`
  }
}];

// Parse Claude Verify response (Attempt 1)
const claude_output = $input.first().json;
const ctx = $('🔧 Initialize Context').first().json;
const rca = $('🔧 Parse RCA Result').first().json.rca;

let verify = {
  resolved: false,
  soll_ist_comparison: 'Verifikation fehlgeschlagen',
  remaining_issues: [],
  verification_method: 'unbekannt'
};

try {
  const text = claude_output.response_text || '{}';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) verify = { ...verify, ...JSON.parse(match[0]) };
} catch(e) {
  verify.remaining_issues = [`Parse error: ${e.message}`];
}

const note_body = `## Verifikation (Versuch 1)\n\n**Behoben:** ${verify.resolved ? '✅ JA' : '❌ NEIN'}\n\n**Soll/Ist-Vergleich:**\n${verify.soll_ist_comparison}\n\n**Prüfmethode:** ${verify.verification_method}${verify.remaining_issues?.length > 0 ? '\n\n**Verbleibende Issues:**\n' + verify.remaining_issues.join('\n') : ''}`;

return [{
  json: {
    ...ctx,
    rca,
    verify,
    resolved: verify.resolved,
    note_title: '✅ Verifikation – Versuch 1',
    note_body
  }
}];

// Build close note summary for successful resolution
const ctx = $('🔧 Initialize Context').first().json;
const rca = $('🔧 Parse RCA Result').first().json.rca;
const verify = $('🔧 Parse Verify Result').first().json.verify;

const close_note = `# Incident automatisch gelöst ✅

**Incident-ID:** ${ctx.incident_id}
**Device:** ${ctx.wer}
**Problem:** ${ctx.was}
**Zeitpunkt:** ${ctx.wan}

## Root Cause
${rca?.rca_text}

## Lösung
${rca?.suggested_approach}

## Verifikation
${verify?.soll_ist_comparison}

Automatisch gelöst in Versuch 1 durch n8n Incident Response Workflow.`;

return [{
  json: {
    ...ctx,
    rca,
    verify,
    close_note,
    attempt_successful: 1,
    bookstack_title: `Incident ${ctx.ticket_id}: ${ctx.title}`,
    bookstack_content: `# ${ctx.title}

**Incident-ID:** ${ctx.incident_id}
**Device:** ${ctx.wer}
**Problem:** ${ctx.was}
**Zeit:** ${ctx.wan}
**Gelöst:** ${new Date().toISOString()}

## Root Cause Analysis
${rca?.rca_text}

**Betroffene Komponente:** ${rca?.affected_component}
**Confidence:** ${rca?.confidence_pct}%

## Lösung
${rca?.suggested_approach}

## Verifikation
${verify?.soll_ist_comparison}

**Prüfmethode:** ${verify?.verification_method}

---
*Automatisch gelöst durch n8n Incident Response Workflow – Versuch 1*`,
    bookstack_tags: JSON.stringify(['incident-response', 'auto-resolved', ctx.system_type, ctx.wer])
  }
}];

