const ctx = $('🔧 Initialize Context').first().json;
const rca1 = $('🔧 Parse RCA Result').first().json.rca;

let rca2 = {
  rca_text: 'Analyse fehlgeschlagen',
  confidence_pct: 0,
  affected_component: 'unbekannt',
  suggested_approach: 'Manuelle Eskalation erforderlich'
};

try {
  const text = claude_output.response_text || '{}';
